{
  "schema": "brainflow.policy.v1",
  "name": "cli_arg_length_mitigation",
  "rules": [
    {
      "id": "prefer_file_payloads",
      "when": "command_args_length_gt_6k",
      "action": "write_payload_to_file_and_pass_path"
    },
    {
      "id": "use_short_paths",
      "when": "windows",
      "action": "prefer_short_temp_paths"
    }
  ],
  "notes": "Policy only; no runtime enforcement unless referenced by workflows or code."
}
